import React, { useState, useMemo } from "react";
import { useFeatures } from "./hooks/useFeature";
import FeatureCard from "./components/FeatureCard";
import FeatureModal from "./components/FeatureModal";
import FilterBar from "./components/FilterBar";
import StatsBar from "./components/StatsBar";
import EmptyState from "./components/EmptyState";
import { STATUSES } from "./utils/costants";

export default function App() {
	const { features } = useFeatures();
	const [filter, setFilter] = useState("All");
	const [selectedFeature, setSelectedFeature] = useState(null);

	const filtered = useMemo(() => {
		if (filter === "All") return features;
		return features.filter((f) => f.status === filter);
	}, [features, filter]);

	const counts = useMemo(() => {
		const c = {};
		STATUSES.forEach((s) => { c[s] = features.filter((f) => f.status === s).length; });
		return c;
	}, [features]);

	return (
		<div className="app app-layout">
			<aside className="sidebar-nav">
				<div className="sidebar-title">Feature Tracker</div>
				<FilterBar active={filter} onChange={setFilter} counts={counts} />
				<button className="btn btn-ghost sidebar-history" onClick={() => { window.history.pushState({}, '', '/history'); window.setAppRoute && window.setAppRoute('history'); }}>View All History</button>
			</aside>
			<main className="main-content">
				{/* ── Header ── */}
				<header className="app-header">
					<div className="header-left">
						<h1 className="app-title">Feature Tracker</h1>
						<p className="app-subtitle">Browse and explore submitted feature requests</p>
					</div>
				</header>

				{/* ── Stats ── */}
				<StatsBar features={features} />

				{/* ── Cards ── */}
				{filtered.length === 0 ? (
					<EmptyState filter={filter} />
				) : (
					<div className="cards-grid">
						{filtered.map((f) => (
							<FeatureCard
								key={f.id}
								feature={f}
								onViewDetails={() => setSelectedFeature(f)}
							/>
						))}
					</div>
				)}

				{/* ── Modal for viewing ── */}
				{selectedFeature !== null && (
					<FeatureModal
						feature={selectedFeature}
						onClose={() => setSelectedFeature(null)}
					/>
				)}
			</main>
		</div>
	);
}
